import requests
from google_adk.tools import tool

@tool
def fetch_user_dashboard(uid: str) -> dict:
    """
    Fetches the user dashboard info.
    """
    try:
        r = requests.get(f"https://api.internal/dash/{uid}", timeout=5)
        r.raise_for_status()
        return {"status": "success", "data": r.json()}
    except requests.exceptions.HTTPError as he:
        return {"status": "failed", "error": f"HTTP Error: {he.response.status_code}"}
    except Exception as e:
        return {"status": "error", "error": str(e)}

from google_adk.tools import tool

@tool
def get_weather_forecast(city: str, days: int = 1) -> dict:
    """
    Retrieves the weather forecast for a target city for a specific number of days.

    Args:
        city: Name of the target location, e.g. 'Boston, MA'
        days: Duration in days to forecast (1 to 5)
    """
    # Mock weather API data
    return {"city": city, "forecast": [{"day": i, "temp": 72 + i, "condition": "Sunny"} for i in range(days)]}

@tool
def convert_currency(amount: float, source_currency: str, target_currency: str) -> dict:
    """
    Converts financial monetary value from a source currency to a target currency.
    """
    rates = {"USD": 1.0, "EUR": 0.92, "GBP": 0.78}
    src = rates.get(source_currency.upper())
    tgt = rates.get(target_currency.upper())
    if not src or not tgt:
        return {"success": False, "error": "Currency code unsupported"}

    value = (amount / src) * tgt
    return {"success": True, "converted_amount": round(value, 2)}
